INSERT INTO interacciones VALUES(188,15,'2026-05-24 22:25:26','seguimiento',NULL,'Arthur puede actualizar estados y resaltar leads con senales de compra o solicitud de cita.','Arthur','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(189,15,'2026-05-24 22:25:26','cierre',NULL,'Perfecto, eso era lo que necesitaba confirmar.','Miguel Angel Torres','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(190,15,'2026-05-24 22:25:26','cierre',NULL,'Queda anotado como prioridad: historial completo y clasificacion de oportunidades.','Arthur','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(191,16,'2026-05-24 22:25:26','nueva_conversacion',NULL,'Hola Arthur, estoy evaluando contratar IA pero tengo dudas de seguridad.','Carolina Urena','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(192,16,'2026-05-24 22:25:26','seguimiento',NULL,'Es normal. Podemos revisar permisos, datos tratados y reglas para proteger informacion sensible.','Arthur','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(193,16,'2026-05-24 22:25:26','seguimiento',NULL,'No quiero que cualquier persona vea datos de clientes.','Carolina Urena','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(194,16,'2026-05-24 22:25:26','seguimiento',NULL,'Se pueden definir accesos por usuario y limitar la informacion visible segun el rol.','Arthur','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(195,16,'2026-05-24 22:25:26','seguimiento',NULL,'Y que pasa si Arthur no sabe responder?','Carolina Urena','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(196,16,'2026-05-24 22:25:26','seguimiento',NULL,'Puede reconocer limites, pedir mas contexto o escalar la conversacion a una persona del equipo.','Arthur','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(197,16,'2026-05-24 22:25:26','seguimiento',NULL,'Eso es importante para no dar respuestas incorrectas.','Carolina Urena','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(198,16,'2026-05-24 22:25:26','seguimiento',NULL,'Exacto. La automatizacion debe operar con reglas claras y escalamiento cuando hay incertidumbre.','Arthur','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(199,16,'2026-05-24 22:25:26','cierre',NULL,'Me gustaria hablar con alguien tecnico.','Carolina Urena','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(200,16,'2026-05-24 22:25:26','cierre',NULL,'Registro la solicitud para una revision tecnica enfocada en seguridad, permisos y manejo de datos.','Arthur','2026-05-24 22:25:26');
INSERT INTO interacciones VALUES(201,1,'2026-05-24 22:40:34','nueva_conversacion',NULL,'Hola Arthur, vi la informacion de Bemantis y quiero saber como me puede ayudar con mis leads.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(202,1,'2026-05-24 22:40:34','seguimiento',NULL,'Hola Juan, soy Arthur. Puedo ayudarte a responder consultas, calificar leads y registrar cada avance en el historial.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(203,1,'2026-05-24 22:40:34','seguimiento',NULL,'Actualmente recibo muchos mensajes por WhatsApp y no siempre puedo responder rapido.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(204,1,'2026-05-24 22:40:34','seguimiento',NULL,'Ese es un buen caso para automatizar. Puedo atender el primer contacto, pedir datos clave y avisar cuando el lead esta listo para seguimiento.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(205,1,'2026-05-24 22:40:34','seguimiento',NULL,'Me interesa que el cliente sienta una conversacion natural, no una respuesta generica.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(206,1,'2026-05-24 22:40:34','seguimiento',NULL,'Podemos configurar el tono, las preguntas frecuentes y las rutas de respuesta para que la conversacion se sienta alineada a tu negocio.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(207,1,'2026-05-24 22:40:34','seguimiento',NULL,'Tambien necesito saber si el sistema puede distinguir entre alguien curioso y alguien listo para comprar.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(208,1,'2026-05-24 22:40:34','seguimiento',NULL,'Si. Puedo identificar senales como urgencia, presupuesto, necesidad concreta y solicitud de cita para marcar oportunidades mas calientes.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(209,1,'2026-05-24 22:40:34','seguimiento',NULL,'Eso ayudaria mucho, porque mi equipo pierde tiempo revisando mensajes sin prioridad.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(210,1,'2026-05-24 22:40:34','seguimiento',NULL,'La idea es ordenar el trabajo comercial: leads frios quedan en seguimiento y los calientes pasan primero al equipo.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(211,1,'2026-05-24 22:40:34','seguimiento',NULL,'Que datos le pedirias al cliente al inicio?','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(212,1,'2026-05-24 22:40:34','seguimiento',NULL,'Normalmente pediria nombre, telefono, necesidad principal, fecha estimada, presupuesto aproximado y canal preferido de contacto.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(213,1,'2026-05-24 22:40:34','seguimiento',NULL,'Podria funcionar tambien fuera de horario?','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(214,1,'2026-05-24 22:40:34','seguimiento',NULL,'Si, puedo responder 24/7 y dejar las conversaciones registradas para que tu equipo las revise al iniciar el dia.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(215,1,'2026-05-24 22:40:34','seguimiento',NULL,'Me preocupa que Arthur responda algo incorrecto si no tiene suficiente informacion.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(216,1,'2026-05-24 22:40:34','seguimiento',NULL,'En esos casos puedo pedir mas contexto o escalar la conversacion a una persona del equipo antes de confirmar algo sensible.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(217,1,'2026-05-24 22:40:34','seguimiento',NULL,'Perfecto. Me gustaria ver una demo con ejemplos parecidos a mis clientes.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(218,1,'2026-05-24 22:40:34','seguimiento',NULL,'Con gusto. Podemos preparar una demo usando preguntas reales de tu negocio y simular el flujo completo del lead.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(219,1,'2026-05-24 22:40:34','cierre',NULL,'Entonces agendemos una llamada esta semana para revisar el alcance.','Juan Perez','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(220,1,'2026-05-24 22:40:34','cierre',NULL,'Listo Juan. Registro el interes para una llamada esta semana y marco este hilo como oportunidad lista para cita.','Arthur','2026-05-24 22:40:34');
INSERT INTO interacciones VALUES(221,22,'2026-05-25 14:17:24','nueva_conversacion',NULL,'Hola Arthur, quiero saber como Bemantis puede ayudarme a responder mas rapido los mensajes de WhatsApp.','Gabriela Solano','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(222,22,'2026-05-25 14:17:24','seguimiento',NULL,'Hola, soy Arthur. Puedo atender consultas iniciales, registrar datos clave y avisar al equipo cuando un lead necesita seguimiento.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(223,22,'2026-05-25 14:17:24','seguimiento',NULL,'En mi negocio muchos clientes escriben fuera del horario laboral.','Gabriela Solano','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(224,22,'2026-05-25 14:17:24','seguimiento',NULL,'Ese es un buen caso de uso. Arthur puede responder 24/7 y dejar cada conversacion documentada.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(225,22,'2026-05-25 14:17:24','seguimiento',NULL,'Tambien quiero saber cuales leads son mas importantes.','Gabriela Solano','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(226,22,'2026-05-25 14:17:24','seguimiento',NULL,'Puedo clasificarlos por intencion, urgencia y datos comerciales para que priorices los contactos con mayor oportunidad.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(227,22,'2026-05-25 14:17:24','seguimiento',NULL,'Perfecto, porque ahora todo queda mezclado en el telefono.','Gabriela Solano','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(228,22,'2026-05-25 14:17:24','seguimiento',NULL,'Con Bemantis cada lead mantiene su historial y estado, lo que facilita retomar la conversacion sin perder contexto.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(229,22,'2026-05-25 14:17:24','cierre',NULL,'Me gustaria ver una demo esta semana.','Gabriela Solano','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(230,22,'2026-05-25 14:17:24','cierre',NULL,'Listo. Registro tu interes para una demo y marco este hilo como oportunidad para agendar cita.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(231,23,'2026-05-25 14:17:24','nueva_conversacion',NULL,'Arthur, recibimos leads desde formulario y quiero darles seguimiento automatico.','Mauricio Esquivel','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(232,23,'2026-05-25 14:17:24','seguimiento',NULL,'Claro. Podemos responder el primer contacto y confirmar datos basicos antes de pasarlos al equipo comercial.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(233,23,'2026-05-25 14:17:24','seguimiento',NULL,'A veces dejan telefono pero no responden cuando llamamos.','Mauricio Esquivel','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(234,23,'2026-05-25 14:17:24','seguimiento',NULL,'Podemos enviar mensajes de seguimiento con un tono natural y opciones sencillas para retomar la conversacion.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(235,23,'2026-05-25 14:17:24','seguimiento',NULL,'No quiero que suene insistente.','Mauricio Esquivel','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(236,23,'2026-05-25 14:17:24','seguimiento',NULL,'Se puede configurar una secuencia amable, con pocos mensajes y salida clara si la persona no desea continuar.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(237,23,'2026-05-25 14:17:24','seguimiento',NULL,'Tambien seria bueno saber si prefieren llamada o WhatsApp.','Mauricio Esquivel','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(238,23,'2026-05-25 14:17:24','seguimiento',NULL,'Arthur puede preguntar el canal preferido y registrar esa preferencia en el historial del lead.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(239,23,'2026-05-25 14:17:24','cierre',NULL,'Eso me interesa para ordenar al equipo.','Mauricio Esquivel','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(240,23,'2026-05-25 14:17:24','cierre',NULL,'Perfecto. Este flujo quedaria enfocado en recuperacion de leads y priorizacion por respuesta.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(241,24,'2026-05-25 14:17:24','nueva_conversacion',NULL,'Hola Arthur, tengo dudas sobre como se integra con mi CRM actual.','Adriana Mendez','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(242,24,'2026-05-25 14:17:24','seguimiento',NULL,'Hola. Podemos revisar si tu CRM permite API, exportacion o algun mecanismo para sincronizar datos.','Arthur','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(243,24,'2026-05-25 14:17:24','seguimiento',NULL,'Por ahora manejamos hojas de calculo y un sistema pequeno.','Adriana Mendez','2026-05-25 14:17:24');
INSERT INTO interacciones VALUES(244,24,'2026-05-25 14:17:25','seguimiento',NULL,'Podemos iniciar con una importacion controlada y luego evaluar una integracion automatica.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(245,24,'2026-05-25 14:17:25','seguimiento',NULL,'Me preocupa que se dupliquen clientes.','Adriana Mendez','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(246,24,'2026-05-25 14:17:25','seguimiento',NULL,'Podemos validar duplicados usando telefono o correo antes de crear nuevos registros.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(247,24,'2026-05-25 14:17:25','seguimiento',NULL,'Tambien quiero que las conversaciones queden asociadas al cliente correcto.','Adriana Mendez','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(248,24,'2026-05-25 14:17:25','seguimiento',NULL,'Cada interaccion se guarda por lead_id, asi el historial queda unido al contacto correspondiente.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(249,24,'2026-05-25 14:17:25','cierre',NULL,'Buenisimo, eso nos evitaria mucho desorden.','Adriana Mendez','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(250,24,'2026-05-25 14:17:25','cierre',NULL,'Entonces el siguiente paso seria revisar una muestra de tus datos y definir los campos necesarios.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(251,25,'2026-05-25 14:17:25','nueva_conversacion',NULL,'Buenas Arthur, quiero automatizar preguntas frecuentes sobre precios y disponibilidad.','Santiago Murillo','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(252,25,'2026-05-25 14:17:25','seguimiento',NULL,'Con gusto. Arthur puede responder preguntas frecuentes y escalar cuando la respuesta dependa de confirmacion humana.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(253,25,'2026-05-25 14:17:25','seguimiento',NULL,'La disponibilidad cambia mucho, no quiero prometer algo incorrecto.','Santiago Murillo','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(254,25,'2026-05-25 14:17:25','seguimiento',NULL,'Podemos usar respuestas prudentes y pedir datos antes de confirmar disponibilidad.','Arthur','2026-05-25 14:17:25');
