INSERT INTO interacciones VALUES(256,25,'2026-05-25 14:17:25','seguimiento',NULL,'Esa pregunta puede ser parte del flujo para calificar mejor la solicitud.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(257,25,'2026-05-25 14:17:25','seguimiento',NULL,'Y si la persona quiere comprar de inmediato?','Santiago Murillo','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(258,25,'2026-05-25 14:17:25','seguimiento',NULL,'Arthur puede marcar el lead como caliente y recomendar atencion prioritaria del equipo.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(259,25,'2026-05-25 14:17:25','cierre',NULL,'Me parece bien, quiero probarlo con algunos casos reales.','Santiago Murillo','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(260,25,'2026-05-25 14:17:25','cierre',NULL,'Perfecto. Podemos preparar una prueba con tus preguntas frecuentes y escenarios de compra inmediata.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(261,26,'2026-05-25 14:17:25','nueva_conversacion',NULL,'Hola Arthur, estoy evaluando IA pero no se si reemplaza a mi equipo.','Patricia Rojas','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(262,26,'2026-05-25 14:17:25','seguimiento',NULL,'No necesariamente. Arthur apoya la primera atencion y deja al equipo humano los casos mas importantes.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(263,26,'2026-05-25 14:17:25','seguimiento',NULL,'Entonces funcionaria como filtro inicial.','Patricia Rojas','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(264,26,'2026-05-25 14:17:25','seguimiento',NULL,'Exacto. Puede responder, ordenar informacion, calificar y escalar cuando detecta una oportunidad real.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(265,26,'2026-05-25 14:17:25','seguimiento',NULL,'Eso nos ayudaria bastante porque recibimos muchas preguntas repetidas.','Patricia Rojas','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(266,26,'2026-05-25 14:17:25','seguimiento',NULL,'Las preguntas repetidas son ideales para automatizar sin perder calidad de atencion.','Arthur','2026-05-25 14:17:25');
