INSERT INTO interacciones VALUES(268,26,'2026-05-25 14:17:25','seguimiento',NULL,'Depende del alcance, pero con preguntas frecuentes claras se puede preparar un primer flujo rapidamente.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(269,26,'2026-05-25 14:17:25','cierre',NULL,'Tengo esas preguntas en un documento.','Patricia Rojas','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(270,26,'2026-05-25 14:17:25','cierre',NULL,'Excelente. Ese documento serviria como base para entrenar el flujo inicial de Arthur.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(271,27,'2026-05-25 14:17:25','nueva_conversacion',NULL,'Arthur, quiero que los leads antiguos vuelvan a responder.','Felipe Araya','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(272,27,'2026-05-25 14:17:25','seguimiento',NULL,'Podemos crear seguimientos para leads sin respuesta y ajustar el mensaje segun su etapa.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(273,27,'2026-05-25 14:17:25','seguimiento',NULL,'Algunos preguntaron hace semanas y luego desaparecieron.','Felipe Araya','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(274,27,'2026-05-25 14:17:25','seguimiento',NULL,'Podemos enviar un mensaje breve preguntando si aun desean informacion o prefieren agendar otro momento.','Arthur','2026-05-25 14:17:25');
