INSERT INTO interacciones VALUES(278,27,'2026-05-25 14:17:25','seguimiento',NULL,'Cada respuesta queda registrada para analizar recuperacion y oportunidad comercial.','Arthur','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(279,27,'2026-05-25 14:17:25','cierre',NULL,'Eso me sirve para reactivar la base.','Felipe Araya','2026-05-25 14:17:25');
INSERT INTO interacciones VALUES(280,27,'2026-05-25 14:17:26','cierre',NULL,'Perfecto. Este hilo queda como caso de recuperacion y seguimiento de leads inactivos.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(281,28,'2026-05-25 14:17:26','nueva_conversacion',NULL,'Buenas Arthur, necesito coordinar citas con personas interesadas.','Karla Cespedes','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(282,28,'2026-05-25 14:17:26','seguimiento',NULL,'Puedo ayudar a pedir disponibilidad, registrar opciones y dejar el hilo listo para confirmacion.','Arthur','2026-05-25 14:17:26');
