INSERT INTO interacciones VALUES(284,28,'2026-05-25 14:17:26','seguimiento',NULL,'Entonces Arthur puede proponer una llamada de 20 minutos y pedir dos opciones de horario.','Arthur','2026-05-25 14:17:26');
