INSERT INTO interacciones VALUES(287,28,'2026-05-25 14:17:26','seguimiento',NULL,'Si alguien pide precio, prefiero hablar primero.','Karla Cespedes','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(288,28,'2026-05-25 14:17:26','seguimiento',NULL,'Arthur puede responder de forma general y sugerir la llamada para ajustar la propuesta.','Arthur','2026-05-25 14:17:26');
