INSERT INTO interacciones VALUES(290,28,'2026-05-25 14:17:26','cierre',NULL,'Listo. Registro este caso como flujo de agenda y calificacion previa a la llamada.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(291,29,'2026-05-25 14:17:26','nueva_conversacion',NULL,'Hola Arthur, mis leads entran por redes sociales y WhatsApp.','Emilio Barrantes','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(292,29,'2026-05-25 14:17:26','seguimiento',NULL,'Podemos iniciar por WhatsApp y luego ampliar el flujo a otros canales si el proceso lo requiere.','Arthur','2026-05-25 14:17:26');
