INSERT INTO interacciones VALUES(294,29,'2026-05-25 14:17:26','seguimiento',NULL,'Tiene sentido. Podemos optimizar la respuesta inicial y la calificacion en ese canal primero.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(295,29,'2026-05-25 14:17:26','seguimiento',NULL,'Quiero saber cuando alguien esta listo para comprar.','Emilio Barrantes','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(296,29,'2026-05-25 14:17:26','seguimiento',NULL,'Podemos definir senales como presupuesto, urgencia, necesidad concreta y solicitud de contacto inmediato.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(297,29,'2026-05-25 14:17:26','seguimiento',NULL,'Y si solo esta comparando opciones?','Emilio Barrantes','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(298,29,'2026-05-25 14:17:26','seguimiento',NULL,'Arthur puede mantenerlo en seguimiento y darle informacion sin presionar una decision.','Arthur','2026-05-25 14:17:26');
