INSERT INTO interacciones VALUES(301,30,'2026-05-25 14:17:26','nueva_conversacion',NULL,'Arthur, necesito que mi equipo vea todo el historial antes de responder.','Monica Hidalgo','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(302,30,'2026-05-25 14:17:26','seguimiento',NULL,'Cada interaccion puede quedar asociada al lead para que el equipo vea el hilo completo.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(303,30,'2026-05-25 14:17:26','seguimiento',NULL,'Eso incluye lo que dice Arthur y lo que dice el cliente?','Monica Hidalgo','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(304,30,'2026-05-25 14:17:26','seguimiento',NULL,'Si. El historial muestra ambos lados de la conversacion para mantener contexto.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(305,30,'2026-05-25 14:17:26','seguimiento',NULL,'A veces dos agentes atienden al mismo contacto.','Monica Hidalgo','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(306,30,'2026-05-25 14:17:26','seguimiento',NULL,'Con el historial centralizado, cualquiera puede retomar sin repetir preguntas.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(307,30,'2026-05-25 14:17:26','seguimiento',NULL,'Tambien necesitamos estados claros.','Monica Hidalgo','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(308,30,'2026-05-25 14:17:26','seguimiento',NULL,'Arthur puede ayudar a actualizar estados como frio, tibio, caliente o cita segun el avance.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(309,30,'2026-05-25 14:17:26','cierre',NULL,'Perfecto, eso nos ordenaria mucho.','Monica Hidalgo','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(310,30,'2026-05-25 14:17:26','cierre',NULL,'Queda registrado como necesidad de historial completo y gestion de estados por lead.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(311,31,'2026-05-25 14:17:26','nueva_conversacion',NULL,'Hola Arthur, tengo preguntas sobre seguridad de datos.','Alonso Vargas','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(312,31,'2026-05-25 14:17:26','seguimiento',NULL,'Es una pregunta importante. Podemos revisar accesos, permisos y manejo de informacion sensible.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(313,31,'2026-05-25 14:17:26','seguimiento',NULL,'No quiero que todos puedan ver todos los clientes.','Alonso Vargas','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(314,31,'2026-05-25 14:17:26','seguimiento',NULL,'Se pueden definir roles o reglas para limitar acceso segun responsabilidad.','Arthur','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(315,31,'2026-05-25 14:17:26','seguimiento',NULL,'Y si Arthur no sabe responder algo?','Alonso Vargas','2026-05-25 14:17:26');
INSERT INTO interacciones VALUES(316,31,'2026-05-25 14:17:27','seguimiento',NULL,'Puede reconocer el limite, pedir mas informacion o escalar a una persona del equipo.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(317,31,'2026-05-25 14:17:27','seguimiento',NULL,'Eso me da mas confianza.','Alonso Vargas','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(318,31,'2026-05-25 14:17:27','seguimiento',NULL,'La automatizacion debe ser util sin inventar informacion ni exponer datos innecesarios.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(319,31,'2026-05-25 14:17:27','cierre',NULL,'Me gustaria una llamada tecnica.','Alonso Vargas','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(320,31,'2026-05-25 14:17:27','cierre',NULL,'Registro la solicitud para una revision tecnica enfocada en seguridad, permisos y escalamiento.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(321,32,'2026-05-25 14:17:27','nueva_conversacion',NULL,'Hola Arthur, quiero saber como Bemantis puede ayudarme a responder mas rapido los mensajes de WhatsApp.','Jimena Corrales','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(322,32,'2026-05-25 14:17:27','seguimiento',NULL,'Hola, soy Arthur. Puedo atender consultas iniciales, registrar datos clave y avisar al equipo cuando un lead necesita seguimiento.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(323,32,'2026-05-25 14:17:27','seguimiento',NULL,'En mi negocio muchos clientes escriben fuera del horario laboral.','Jimena Corrales','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(324,32,'2026-05-25 14:17:27','seguimiento',NULL,'Ese es un buen caso de uso. Arthur puede responder 24/7 y dejar cada conversacion documentada.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(325,32,'2026-05-25 14:17:27','seguimiento',NULL,'Tambien quiero saber cuales leads son mas importantes.','Jimena Corrales','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(326,32,'2026-05-25 14:17:27','seguimiento',NULL,'Puedo clasificarlos por intencion, urgencia y datos comerciales para que priorices los contactos con mayor oportunidad.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(327,32,'2026-05-25 14:17:27','seguimiento',NULL,'Perfecto, porque ahora todo queda mezclado en el telefono.','Jimena Corrales','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(328,32,'2026-05-25 14:17:27','seguimiento',NULL,'Con Bemantis cada lead mantiene su historial y estado, lo que facilita retomar la conversacion sin perder contexto.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(329,32,'2026-05-25 14:17:27','cierre',NULL,'Me gustaria ver una demo esta semana.','Jimena Corrales','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(330,32,'2026-05-25 14:17:27','cierre',NULL,'Listo. Registro tu interes para una demo y marco este hilo como oportunidad para agendar cita.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(331,33,'2026-05-25 14:17:27','nueva_conversacion',NULL,'Arthur, recibimos leads desde formulario y quiero darles seguimiento automatico.','Rodrigo Paniagua','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(332,33,'2026-05-25 14:17:27','seguimiento',NULL,'Claro. Podemos responder el primer contacto y confirmar datos basicos antes de pasarlos al equipo comercial.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(333,33,'2026-05-25 14:17:27','seguimiento',NULL,'A veces dejan telefono pero no responden cuando llamamos.','Rodrigo Paniagua','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(334,33,'2026-05-25 14:17:27','seguimiento',NULL,'Podemos enviar mensajes de seguimiento con un tono natural y opciones sencillas para retomar la conversacion.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(335,33,'2026-05-25 14:17:27','seguimiento',NULL,'No quiero que suene insistente.','Rodrigo Paniagua','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(336,33,'2026-05-25 14:17:27','seguimiento',NULL,'Se puede configurar una secuencia amable, con pocos mensajes y salida clara si la persona no desea continuar.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(337,33,'2026-05-25 14:17:27','seguimiento',NULL,'Tambien seria bueno saber si prefieren llamada o WhatsApp.','Rodrigo Paniagua','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(338,33,'2026-05-25 14:17:27','seguimiento',NULL,'Arthur puede preguntar el canal preferido y registrar esa preferencia en el historial del lead.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(339,33,'2026-05-25 14:17:27','cierre',NULL,'Eso me interesa para ordenar al equipo.','Rodrigo Paniagua','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(340,33,'2026-05-25 14:17:27','cierre',NULL,'Perfecto. Este flujo quedaria enfocado en recuperacion de leads y priorizacion por respuesta.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(341,34,'2026-05-25 14:17:27','nueva_conversacion',NULL,'Hola Arthur, tengo dudas sobre como se integra con mi CRM actual.','Daniela Castro','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(342,34,'2026-05-25 14:17:27','seguimiento',NULL,'Hola. Podemos revisar si tu CRM permite API, exportacion o algun mecanismo para sincronizar datos.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(343,34,'2026-05-25 14:17:27','seguimiento',NULL,'Por ahora manejamos hojas de calculo y un sistema pequeno.','Daniela Castro','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(344,34,'2026-05-25 14:17:27','seguimiento',NULL,'Podemos iniciar con una importacion controlada y luego evaluar una integracion automatica.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(345,34,'2026-05-25 14:17:27','seguimiento',NULL,'Me preocupa que se dupliquen clientes.','Daniela Castro','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(346,34,'2026-05-25 14:17:27','seguimiento',NULL,'Podemos validar duplicados usando telefono o correo antes de crear nuevos registros.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(347,34,'2026-05-25 14:17:27','seguimiento',NULL,'Tambien quiero que las conversaciones queden asociadas al cliente correcto.','Daniela Castro','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(348,34,'2026-05-25 14:17:27','seguimiento',NULL,'Cada interaccion se guarda por lead_id, asi el historial queda unido al contacto correspondiente.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(349,34,'2026-05-25 14:17:27','cierre',NULL,'Buenisimo, eso nos evitaria mucho desorden.','Daniela Castro','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(350,34,'2026-05-25 14:17:27','cierre',NULL,'Entonces el siguiente paso seria revisar una muestra de tus datos y definir los campos necesarios.','Arthur','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(351,35,'2026-05-25 14:17:27','nueva_conversacion',NULL,'Buenas Arthur, quiero automatizar preguntas frecuentes sobre precios y disponibilidad.','Hector Aguilar','2026-05-25 14:17:27');
INSERT INTO interacciones VALUES(352,35,'2026-05-25 14:17:28','seguimiento',NULL,'Con gusto. Arthur puede responder preguntas frecuentes y escalar cuando la respuesta dependa de confirmacion humana.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(353,35,'2026-05-25 14:17:28','seguimiento',NULL,'La disponibilidad cambia mucho, no quiero prometer algo incorrecto.','Hector Aguilar','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(354,35,'2026-05-25 14:17:28','seguimiento',NULL,'Podemos usar respuestas prudentes y pedir datos antes de confirmar disponibilidad.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(355,35,'2026-05-25 14:17:28','seguimiento',NULL,'Tambien necesito que pregunte por fecha deseada.','Hector Aguilar','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(356,35,'2026-05-25 14:17:28','seguimiento',NULL,'Esa pregunta puede ser parte del flujo para calificar mejor la solicitud.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(357,35,'2026-05-25 14:17:28','seguimiento',NULL,'Y si la persona quiere comprar de inmediato?','Hector Aguilar','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(358,35,'2026-05-25 14:17:28','seguimiento',NULL,'Arthur puede marcar el lead como caliente y recomendar atencion prioritaria del equipo.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(359,35,'2026-05-25 14:17:28','cierre',NULL,'Me parece bien, quiero probarlo con algunos casos reales.','Hector Aguilar','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(360,35,'2026-05-25 14:17:28','cierre',NULL,'Perfecto. Podemos preparar una prueba con tus preguntas frecuentes y escenarios de compra inmediata.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(361,36,'2026-05-25 14:17:28','nueva_conversacion',NULL,'Hola Arthur, estoy evaluando IA pero no se si reemplaza a mi equipo.','Camila Soto','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(362,36,'2026-05-25 14:17:28','seguimiento',NULL,'No necesariamente. Arthur apoya la primera atencion y deja al equipo humano los casos mas importantes.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(363,36,'2026-05-25 14:17:28','seguimiento',NULL,'Entonces funcionaria como filtro inicial.','Camila Soto','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(364,36,'2026-05-25 14:17:28','seguimiento',NULL,'Exacto. Puede responder, ordenar informacion, calificar y escalar cuando detecta una oportunidad real.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(365,36,'2026-05-25 14:17:28','seguimiento',NULL,'Eso nos ayudaria bastante porque recibimos muchas preguntas repetidas.','Camila Soto','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(366,36,'2026-05-25 14:17:28','seguimiento',NULL,'Las preguntas repetidas son ideales para automatizar sin perder calidad de atencion.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(367,36,'2026-05-25 14:17:28','seguimiento',NULL,'Cuanto tiempo toma configurarlo?','Camila Soto','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(368,36,'2026-05-25 14:17:28','seguimiento',NULL,'Depende del alcance, pero con preguntas frecuentes claras se puede preparar un primer flujo rapidamente.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(369,36,'2026-05-25 14:17:28','cierre',NULL,'Tengo esas preguntas en un documento.','Camila Soto','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(370,36,'2026-05-25 14:17:28','cierre',NULL,'Excelente. Ese documento serviria como base para entrenar el flujo inicial de Arthur.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(371,37,'2026-05-25 14:17:28','nueva_conversacion',NULL,'Arthur, quiero que los leads antiguos vuelvan a responder.','Joaquin Salazar','2026-05-25 14:17:28');
