INSERT INTO interacciones VALUES(378,37,'2026-05-25 14:17:28','seguimiento',NULL,'Cada respuesta queda registrada para analizar recuperacion y oportunidad comercial.','Arthur','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(379,37,'2026-05-25 14:17:28','cierre',NULL,'Eso me sirve para reactivar la base.','Joaquin Salazar','2026-05-25 14:17:28');
INSERT INTO interacciones VALUES(380,37,'2026-05-25 14:17:28','cierre',NULL,'Perfecto. Este hilo queda como caso de recuperacion y seguimiento de leads inactivos.','Arthur','2026-05-25 14:17:28');
