INSERT INTO interacciones VALUES(392,39,'2026-05-25 14:17:29','seguimiento',NULL,'Podemos iniciar por WhatsApp y luego ampliar el flujo a otros canales si el proceso lo requiere.','Arthur','2026-05-25 14:17:29');
