INSERT INTO interacciones VALUES(396,39,'2026-05-25 14:17:29','seguimiento',NULL,'Podemos definir senales como presupuesto, urgencia, necesidad concreta y solicitud de contacto inmediato.','Arthur','2026-05-25 14:17:29');
