INSERT INTO interacciones VALUES(421,42,'2026-05-25 14:17:29','nueva_conversacion',NULL,'Hola Arthur, quiero saber como Bemantis puede ayudarme a responder mas rapido los mensajes de WhatsApp.','Laura Brenes','2026-05-25 14:17:29');
INSERT INTO interacciones VALUES(422,42,'2026-05-25 14:17:30','seguimiento',NULL,'Hola, soy Arthur. Puedo atender consultas iniciales, registrar datos clave y avisar al equipo cuando un lead necesita seguimiento.','Arthur','2026-05-25 14:17:30');
