INSERT INTO interacciones VALUES(427,42,'2026-05-25 14:17:30','seguimiento',NULL,'Perfecto, porque ahora todo queda mezclado en el telefono.','Laura Brenes','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(428,42,'2026-05-25 14:17:30','seguimiento',NULL,'Con Bemantis cada lead mantiene su historial y estado, lo que facilita retomar la conversacion sin perder contexto.','Arthur','2026-05-25 14:17:30');
