INSERT INTO interacciones VALUES(434,43,'2026-05-25 14:17:30','seguimiento',NULL,'Podemos enviar mensajes de seguimiento con un tono natural y opciones sencillas para retomar la conversacion.','Arthur','2026-05-25 14:17:30');
