INSERT INTO interacciones VALUES(436,43,'2026-05-25 14:17:30','seguimiento',NULL,'Se puede configurar una secuencia amable, con pocos mensajes y salida clara si la persona no desea continuar.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(437,43,'2026-05-25 14:17:30','seguimiento',NULL,'Tambien seria bueno saber si prefieren llamada o WhatsApp.','Pablo Hernandez','2026-05-25 14:17:30');
