INSERT INTO interacciones VALUES(439,43,'2026-05-25 14:17:30','cierre',NULL,'Eso me interesa para ordenar al equipo.','Pablo Hernandez','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(440,43,'2026-05-25 14:17:30','cierre',NULL,'Perfecto. Este flujo quedaria enfocado en recuperacion de leads y priorizacion por respuesta.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(441,44,'2026-05-25 14:17:30','nueva_conversacion',NULL,'Hola Arthur, tengo dudas sobre como se integra con mi CRM actual.','Sofia Zamora','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(442,44,'2026-05-25 14:17:30','seguimiento',NULL,'Hola. Podemos revisar si tu CRM permite API, exportacion o algun mecanismo para sincronizar datos.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(443,44,'2026-05-25 14:17:30','seguimiento',NULL,'Por ahora manejamos hojas de calculo y un sistema pequeno.','Sofia Zamora','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(444,44,'2026-05-25 14:17:30','seguimiento',NULL,'Podemos iniciar con una importacion controlada y luego evaluar una integracion automatica.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(445,44,'2026-05-25 14:17:30','seguimiento',NULL,'Me preocupa que se dupliquen clientes.','Sofia Zamora','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(446,44,'2026-05-25 14:17:30','seguimiento',NULL,'Podemos validar duplicados usando telefono o correo antes de crear nuevos registros.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(447,44,'2026-05-25 14:17:30','seguimiento',NULL,'Tambien quiero que las conversaciones queden asociadas al cliente correcto.','Sofia Zamora','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(448,44,'2026-05-25 14:17:30','seguimiento',NULL,'Cada interaccion se guarda por lead_id, asi el historial queda unido al contacto correspondiente.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(449,44,'2026-05-25 14:17:30','cierre',NULL,'Buenisimo, eso nos evitaria mucho desorden.','Sofia Zamora','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(450,44,'2026-05-25 14:17:30','cierre',NULL,'Entonces el siguiente paso seria revisar una muestra de tus datos y definir los campos necesarios.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(451,45,'2026-05-25 14:17:30','nueva_conversacion',NULL,'Buenas Arthur, quiero automatizar preguntas frecuentes sobre precios y disponibilidad.','Ricardo Segura','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(452,45,'2026-05-25 14:17:30','seguimiento',NULL,'Con gusto. Arthur puede responder preguntas frecuentes y escalar cuando la respuesta dependa de confirmacion humana.','Arthur','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(453,45,'2026-05-25 14:17:30','seguimiento',NULL,'La disponibilidad cambia mucho, no quiero prometer algo incorrecto.','Ricardo Segura','2026-05-25 14:17:30');
INSERT INTO interacciones VALUES(454,45,'2026-05-25 14:17:30','seguimiento',NULL,'Podemos usar respuestas prudentes y pedir datos antes de confirmar disponibilidad.','Arthur','2026-05-25 14:17:30');
