INSERT INTO interacciones VALUES(459,45,'2026-05-25 14:17:31','cierre',NULL,'Me parece bien, quiero probarlo con algunos casos reales.','Ricardo Segura','2026-05-25 14:17:31');
INSERT INTO interacciones VALUES(460,45,'2026-05-25 14:17:31','cierre',NULL,'Perfecto. Podemos preparar una prueba con tus preguntas frecuentes y escenarios de compra inmediata.','Arthur','2026-05-25 14:17:31');
