INSERT INTO interacciones VALUES(462,46,'2026-05-25 14:17:31','seguimiento',NULL,'No necesariamente. Arthur apoya la primera atencion y deja al equipo humano los casos mas importantes.','Arthur','2026-05-25 14:17:31');
