INSERT INTO interacciones VALUES(468,46,'2026-05-25 14:17:31','seguimiento',NULL,'Depende del alcance, pero con preguntas frecuentes claras se puede preparar un primer flujo rapidamente.','Arthur','2026-05-25 14:17:31');
INSERT INTO interacciones VALUES(469,46,'2026-05-25 14:17:31','cierre',NULL,'Tengo esas preguntas en un documento.','Mariana Alfaro','2026-05-25 14:17:31');
INSERT INTO interacciones VALUES(470,46,'2026-05-25 14:17:31','cierre',NULL,'Excelente. Ese documento serviria como base para entrenar el flujo inicial de Arthur.','Arthur','2026-05-25 14:17:31');
