INSERT INTO interacciones VALUES(482,48,'2026-05-25 14:17:31','seguimiento',NULL,'Puedo ayudar a pedir disponibilidad, registrar opciones y dejar el hilo listo para confirmacion.','Arthur','2026-05-25 14:17:31');
