INSERT INTO interacciones VALUES(534,53,'2026-05-25 14:17:33','seguimiento',NULL,'Podemos enviar mensajes de seguimiento con un tono natural y opciones sencillas para retomar la conversacion.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(535,53,'2026-05-25 14:17:33','seguimiento',NULL,'No quiero que suene insistente.','Esteban Vega','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(536,53,'2026-05-25 14:17:33','seguimiento',NULL,'Se puede configurar una secuencia amable, con pocos mensajes y salida clara si la persona no desea continuar.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(537,53,'2026-05-25 14:17:33','seguimiento',NULL,'Tambien seria bueno saber si prefieren llamada o WhatsApp.','Esteban Vega','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(538,53,'2026-05-25 14:17:33','seguimiento',NULL,'Arthur puede preguntar el canal preferido y registrar esa preferencia en el historial del lead.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(539,53,'2026-05-25 14:17:33','cierre',NULL,'Eso me interesa para ordenar al equipo.','Esteban Vega','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(540,53,'2026-05-25 14:17:33','cierre',NULL,'Perfecto. Este flujo quedaria enfocado en recuperacion de leads y priorizacion por respuesta.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(541,54,'2026-05-25 14:17:33','nueva_conversacion',NULL,'Hola Arthur, tengo dudas sobre como se integra con mi CRM actual.','Carolina Marin','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(542,54,'2026-05-25 14:17:33','seguimiento',NULL,'Hola. Podemos revisar si tu CRM permite API, exportacion o algun mecanismo para sincronizar datos.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(543,54,'2026-05-25 14:17:33','seguimiento',NULL,'Por ahora manejamos hojas de calculo y un sistema pequeno.','Carolina Marin','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(544,54,'2026-05-25 14:17:33','seguimiento',NULL,'Podemos iniciar con una importacion controlada y luego evaluar una integracion automatica.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(545,54,'2026-05-25 14:17:33','seguimiento',NULL,'Me preocupa que se dupliquen clientes.','Carolina Marin','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(546,54,'2026-05-25 14:17:33','seguimiento',NULL,'Podemos validar duplicados usando telefono o correo antes de crear nuevos registros.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(547,54,'2026-05-25 14:17:33','seguimiento',NULL,'Tambien quiero que las conversaciones queden asociadas al cliente correcto.','Carolina Marin','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(548,54,'2026-05-25 14:17:33','seguimiento',NULL,'Cada interaccion se guarda por lead_id, asi el historial queda unido al contacto correspondiente.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(549,54,'2026-05-25 14:17:33','cierre',NULL,'Buenisimo, eso nos evitaria mucho desorden.','Carolina Marin','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(550,54,'2026-05-25 14:17:33','cierre',NULL,'Entonces el siguiente paso seria revisar una muestra de tus datos y definir los campos necesarios.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(551,55,'2026-05-25 14:17:33','nueva_conversacion',NULL,'Buenas Arthur, quiero automatizar preguntas frecuentes sobre precios y disponibilidad.','Alejandro Fonseca','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(552,55,'2026-05-25 14:17:33','seguimiento',NULL,'Con gusto. Arthur puede responder preguntas frecuentes y escalar cuando la respuesta dependa de confirmacion humana.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(553,55,'2026-05-25 14:17:33','seguimiento',NULL,'La disponibilidad cambia mucho, no quiero prometer algo incorrecto.','Alejandro Fonseca','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(554,55,'2026-05-25 14:17:33','seguimiento',NULL,'Podemos usar respuestas prudentes y pedir datos antes de confirmar disponibilidad.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(555,55,'2026-05-25 14:17:33','seguimiento',NULL,'Tambien necesito que pregunte por fecha deseada.','Alejandro Fonseca','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(556,55,'2026-05-25 14:17:33','seguimiento',NULL,'Esa pregunta puede ser parte del flujo para calificar mejor la solicitud.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(557,55,'2026-05-25 14:17:33','seguimiento',NULL,'Y si la persona quiere comprar de inmediato?','Alejandro Fonseca','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(558,55,'2026-05-25 14:17:33','seguimiento',NULL,'Arthur puede marcar el lead como caliente y recomendar atencion prioritaria del equipo.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(559,55,'2026-05-25 14:17:33','cierre',NULL,'Me parece bien, quiero probarlo con algunos casos reales.','Alejandro Fonseca','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(560,55,'2026-05-25 14:17:33','cierre',NULL,'Perfecto. Podemos preparar una prueba con tus preguntas frecuentes y escenarios de compra inmediata.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(561,56,'2026-05-25 14:17:33','nueva_conversacion',NULL,'Hola Arthur, estoy evaluando IA pero no se si reemplaza a mi equipo.','Melissa Acuna','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(562,56,'2026-05-25 14:17:33','seguimiento',NULL,'No necesariamente. Arthur apoya la primera atencion y deja al equipo humano los casos mas importantes.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(563,56,'2026-05-25 14:17:33','seguimiento',NULL,'Entonces funcionaria como filtro inicial.','Melissa Acuna','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(564,56,'2026-05-25 14:17:33','seguimiento',NULL,'Exacto. Puede responder, ordenar informacion, calificar y escalar cuando detecta una oportunidad real.','Arthur','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(565,56,'2026-05-25 14:17:33','seguimiento',NULL,'Eso nos ayudaria bastante porque recibimos muchas preguntas repetidas.','Melissa Acuna','2026-05-25 14:17:33');
INSERT INTO interacciones VALUES(566,56,'2026-05-25 14:17:34','seguimiento',NULL,'Las preguntas repetidas son ideales para automatizar sin perder calidad de atencion.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(567,56,'2026-05-25 14:17:34','seguimiento',NULL,'Cuanto tiempo toma configurarlo?','Melissa Acuna','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(568,56,'2026-05-25 14:17:34','seguimiento',NULL,'Depende del alcance, pero con preguntas frecuentes claras se puede preparar un primer flujo rapidamente.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(569,56,'2026-05-25 14:17:34','cierre',NULL,'Tengo esas preguntas en un documento.','Melissa Acuna','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(570,56,'2026-05-25 14:17:34','cierre',NULL,'Excelente. Ese documento serviria como base para entrenar el flujo inicial de Arthur.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(571,57,'2026-05-25 14:17:34','nueva_conversacion',NULL,'Arthur, quiero que los leads antiguos vuelvan a responder.','Rafael Delgado','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(572,57,'2026-05-25 14:17:34','seguimiento',NULL,'Podemos crear seguimientos para leads sin respuesta y ajustar el mensaje segun su etapa.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(573,57,'2026-05-25 14:17:34','seguimiento',NULL,'Algunos preguntaron hace semanas y luego desaparecieron.','Rafael Delgado','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(574,57,'2026-05-25 14:17:34','seguimiento',NULL,'Podemos enviar un mensaje breve preguntando si aun desean informacion o prefieren agendar otro momento.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(575,57,'2026-05-25 14:17:34','seguimiento',NULL,'No quiero contactar a alguien que ya dijo que no.','Rafael Delgado','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(576,57,'2026-05-25 14:17:34','seguimiento',NULL,'Se pueden respetar preferencias y detener seguimientos cuando el lead no quiere continuar.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(577,57,'2026-05-25 14:17:34','seguimiento',NULL,'Tambien quiero medir quienes responden.','Rafael Delgado','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(578,57,'2026-05-25 14:17:34','seguimiento',NULL,'Cada respuesta queda registrada para analizar recuperacion y oportunidad comercial.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(579,57,'2026-05-25 14:17:34','cierre',NULL,'Eso me sirve para reactivar la base.','Rafael Delgado','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(580,57,'2026-05-25 14:17:34','cierre',NULL,'Perfecto. Este hilo queda como caso de recuperacion y seguimiento de leads inactivos.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(581,58,'2026-05-25 14:17:34','nueva_conversacion',NULL,'Buenas Arthur, necesito coordinar citas con personas interesadas.','Andrea Ulate','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(582,58,'2026-05-25 14:17:34','seguimiento',NULL,'Puedo ayudar a pedir disponibilidad, registrar opciones y dejar el hilo listo para confirmacion.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(583,58,'2026-05-25 14:17:34','seguimiento',NULL,'Normalmente ofrecemos llamadas de 20 minutos.','Andrea Ulate','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(584,58,'2026-05-25 14:17:34','seguimiento',NULL,'Entonces Arthur puede proponer una llamada de 20 minutos y pedir dos opciones de horario.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(585,58,'2026-05-25 14:17:34','seguimiento',NULL,'Tambien deberia preguntar que tema quieren revisar.','Andrea Ulate','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(586,58,'2026-05-25 14:17:34','seguimiento',NULL,'Correcto. Podemos pedir tema principal para que la llamada sea mas productiva.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(587,58,'2026-05-25 14:17:34','seguimiento',NULL,'Si alguien pide precio, prefiero hablar primero.','Andrea Ulate','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(588,58,'2026-05-25 14:17:34','seguimiento',NULL,'Arthur puede responder de forma general y sugerir la llamada para ajustar la propuesta.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(589,58,'2026-05-25 14:17:34','cierre',NULL,'Muy bien, quiero ese flujo.','Andrea Ulate','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(590,58,'2026-05-25 14:17:34','cierre',NULL,'Listo. Registro este caso como flujo de agenda y calificacion previa a la llamada.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(591,59,'2026-05-25 14:17:34','nueva_conversacion',NULL,'Hola Arthur, mis leads entran por redes sociales y WhatsApp.','Tomas Valverde','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(592,59,'2026-05-25 14:17:34','seguimiento',NULL,'Podemos iniciar por WhatsApp y luego ampliar el flujo a otros canales si el proceso lo requiere.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(593,59,'2026-05-25 14:17:34','seguimiento',NULL,'WhatsApp es prioridad porque ahi cierran mas rapido.','Tomas Valverde','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(594,59,'2026-05-25 14:17:34','seguimiento',NULL,'Tiene sentido. Podemos optimizar la respuesta inicial y la calificacion en ese canal primero.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(595,59,'2026-05-25 14:17:34','seguimiento',NULL,'Quiero saber cuando alguien esta listo para comprar.','Tomas Valverde','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(596,59,'2026-05-25 14:17:34','seguimiento',NULL,'Podemos definir senales como presupuesto, urgencia, necesidad concreta y solicitud de contacto inmediato.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(597,59,'2026-05-25 14:17:34','seguimiento',NULL,'Y si solo esta comparando opciones?','Tomas Valverde','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(598,59,'2026-05-25 14:17:34','seguimiento',NULL,'Arthur puede mantenerlo en seguimiento y darle informacion sin presionar una decision.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(599,59,'2026-05-25 14:17:34','cierre',NULL,'Ese balance me gusta.','Tomas Valverde','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(600,59,'2026-05-25 14:17:34','cierre',NULL,'Lo configuramos con un tono consultivo y cercano para cuidar la experiencia del lead.','Arthur','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(601,60,'2026-05-25 14:17:34','nueva_conversacion',NULL,'Arthur, necesito que mi equipo vea todo el historial antes de responder.','Isabel Nunez','2026-05-25 14:17:34');
INSERT INTO interacciones VALUES(602,60,'2026-05-25 14:17:35','seguimiento',NULL,'Cada interaccion puede quedar asociada al lead para que el equipo vea el hilo completo.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(603,60,'2026-05-25 14:17:35','seguimiento',NULL,'Eso incluye lo que dice Arthur y lo que dice el cliente?','Isabel Nunez','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(604,60,'2026-05-25 14:17:35','seguimiento',NULL,'Si. El historial muestra ambos lados de la conversacion para mantener contexto.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(605,60,'2026-05-25 14:17:35','seguimiento',NULL,'A veces dos agentes atienden al mismo contacto.','Isabel Nunez','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(606,60,'2026-05-25 14:17:35','seguimiento',NULL,'Con el historial centralizado, cualquiera puede retomar sin repetir preguntas.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(607,60,'2026-05-25 14:17:35','seguimiento',NULL,'Tambien necesitamos estados claros.','Isabel Nunez','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(608,60,'2026-05-25 14:17:35','seguimiento',NULL,'Arthur puede ayudar a actualizar estados como frio, tibio, caliente o cita segun el avance.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(609,60,'2026-05-25 14:17:35','cierre',NULL,'Perfecto, eso nos ordenaria mucho.','Isabel Nunez','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(610,60,'2026-05-25 14:17:35','cierre',NULL,'Queda registrado como necesidad de historial completo y gestion de estados por lead.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(611,61,'2026-05-25 14:17:35','nueva_conversacion',NULL,'Hola Arthur, tengo preguntas sobre seguridad de datos.','Javier Leon','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(612,61,'2026-05-25 14:17:35','seguimiento',NULL,'Es una pregunta importante. Podemos revisar accesos, permisos y manejo de informacion sensible.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(613,61,'2026-05-25 14:17:35','seguimiento',NULL,'No quiero que todos puedan ver todos los clientes.','Javier Leon','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(614,61,'2026-05-25 14:17:35','seguimiento',NULL,'Se pueden definir roles o reglas para limitar acceso segun responsabilidad.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(615,61,'2026-05-25 14:17:35','seguimiento',NULL,'Y si Arthur no sabe responder algo?','Javier Leon','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(616,61,'2026-05-25 14:17:35','seguimiento',NULL,'Puede reconocer el limite, pedir mas informacion o escalar a una persona del equipo.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(617,61,'2026-05-25 14:17:35','seguimiento',NULL,'Eso me da mas confianza.','Javier Leon','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(618,61,'2026-05-25 14:17:35','seguimiento',NULL,'La automatizacion debe ser util sin inventar informacion ni exponer datos innecesarios.','Arthur','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(619,61,'2026-05-25 14:17:35','cierre',NULL,'Me gustaria una llamada tecnica.','Javier Leon','2026-05-25 14:17:35');
INSERT INTO interacciones VALUES(620,61,'2026-05-25 14:17:35','cierre',NULL,'Registro la solicitud para una revision tecnica enfocada en seguridad, permisos y escalamiento.','Arthur','2026-05-25 14:17:35');
